export function lazyDialect<T>(
	self: { dialect?: T; dialectConfig: any },
	DialectClass: new (config: any) => T,
): T {
	if (!self.dialect) {
		self.dialect = new DialectClass(self.dialectConfig);
	}

	return self.dialect;
}

